  1→import {useLocation, useNavigate } from 'react-router-dom';
  2→import './profilepostcards.css';
  3→import { useInfiniteQuery } from '@tanstack/react-query';
  4→import { useEffect, useState, useCallback } from 'react';
  5→import { MoonLoader } from 'react-spinners';
  6→import { motion } from 'framer-motion';
  7→import ParseContent from '../parseData';
  8→import { useInView } from 'react-intersection-observer';
  9→import { handleCLickContent } from '../../../../../helpers/handleClicks';
 10→import { useAuth } from '../../../../Context/useAuth';
 11→import { getVisitedUserJournals } from '../../../../../API/Api';
 12→import { useAddViewsMutation } from '../../../../utils/useMutation';
 13→import VerifiedBadge from '../../../Badge/VerifiedBadge';
 14→import { handleImageFallback } from '../../../../utils/handleImageFallback';
 15→import { getCanvasPreview } from '../../../../utils/canvasDoc';
 16→import CanvasPreview from '../CanvasPreview/CanvasPreview';
 17→
 18→const VisitedProfilePostCards = () =>{
 19→    const location = useLocation();
 20→    const userId = location.state?.userId || new URLSearchParams(location.search).get('userId');
 21→    const {user, session} = useAuth();
 22→
 23→    const navigate = useNavigate();
 24→
 25→    const {ref, inView} = useInView({
 26→        threshold: 0.2
 27→    })
 28→
 29→    const {data: journalData, isLoading: isLoadingJournals, isFetchingNextPage, fetchNextPage, hasNextPage,} = useInfiniteQuery({
 30→        queryKey: ['visitedProfileJournals', userId, user?.userData?.[0]?.id],
 31→        queryFn: ({pageParam = null, queryKey}) => getVisitedUserJournals(pageParam, 5, queryKey[1], queryKey[2]),
 32→        getNextPageParam: (lastPage) => {
 33→            if(lastPage.hasMore){
 34→                const lastJournal = lastPage?.data[lastPage?.data.length - 1]
 35→                return new Date(lastJournal.created_at).toISOString();
 36→            } else {
 37→                return undefined
 38→            }
 39→        },
 40→        enabled: !!userId,
 41→        refetchOnWindowFocus: false,
 42→        staleTime: 1000 * 60 * 5
 43→    })
 44→
 45→    const clickContent = handleCLickContent(navigate);
 46→    const mutateViews = useAddViewsMutation(session);
 47→    const viewContent = (e, jsonbContent,wholeText, title, userId, name, avatar, created_at, journalId, isLiked, commentsCount, isBookmarked, likesCount, bookmarksCount, badge, postType = null, canvasDoc = null, userReaction = null, reactionCount = 0) =>{
 48→        const formadata = new FormData();
 49→        formadata.append('journalId', journalId)
 50→        mutateViews.mutate(formadata);
 51→
 52→        clickContent(e, jsonbContent,wholeText, title, userId, name, avatar, created_at, journalId, isLiked, commentsCount, isBookmarked, likesCount, bookmarksCount, badge, postType, canvasDoc, userReaction, reactionCount);
 53→    }
 54→
 55→    useEffect(() =>{
 56→        // console.log(userId)
 57→    },[userId])
 58→
 59→    const [viewMode, setViewMode] = useState('grid');
 60→
 61→    useEffect(() =>{
 62→        if(!isFetchingNextPage && hasNextPage && inView){
 63→            fetchNextPage();
 64→        }
 65→    }, [inView, fetchNextPage, isFetchingNextPage, hasNextPage])
 66→
 67→    const handleToggleView = useCallback(() => {
 68→        setViewMode((prev) => (prev === 'list' ? 'grid' : 'list'));
 69→    }, []);
 70→
 71→    const journals = journalData?.pages.flatMap((page) => page.data) || [];
 72→
 73→
 74→   if(isLoadingJournals){
 75→        return(
 76→            <>
 77→            <div className='profile-postcards-loading-container'>
 78→                <MoonLoader loading={isLoadingJournals} color="var(--loader-color)" size={20} speedMultiplier={0.5}/>
 79→            </div>
 80→            </>
 81→        )
 82→    }
 83→    
 84→
 85→    if(journalData && !journals?.length > 0){
 86→        return (
 87→            <div className='profile-postcards-loading-container'>
 88→                No post available!
 89→            </div>
 90→        )
 91→    }
 92→
 93→    return(
 94→        <>
 95→        <div className='profile-postcards-parent-container'>
 96→            <div className="postcards-header-row">
 97→                <h2 className="postcards-heading">
 98→                    Posts <span className="postcards-count">({journals.length})</span>
 99→                </h2>
100→                <div className="postcards-header-actions">
101→                    <button
102→                        className={`postcards-view-toggle-btn ${viewMode === 'grid' ? 'is-active' : ''}`}
103→                        onClick={handleToggleView}
104→                        title={viewMode === 'grid' ? 'Switch to list' : 'Switch to grid'}
105→                    >
106→                        {viewMode === 'grid' ? (
107→                            <svg xmlns="http://www.w3.org/2000/svg" height="20px" viewBox="0 -960 960 960" width="20px" fill="currentColor"><path d="M120-520v-320h320v320H120Zm0 400v-320h320v320H120Zm400-400v-320h320v320H520Zm0 400v-320h320v320H520Z"/></svg>
108→                        ) : (
109→                            <svg xmlns="http://www.w3.org/2000/svg" height="20px" viewBox="0 -960 960 960" width="20px" fill="currentColor"><path d="M120-200v-560h720v560H120Z"/></svg>
110→                        )}
111→                    </button>
112→                </div>
113→            </div>
114→
115→            {viewMode === 'grid' ? (
116→                <div className="postcards-grid-view">
117→                    {journals.map((journal) => {
118→                        const isCanvasPost = journal?.post_type === 'canvas';
119→                        const parsedContent = ParseContent(journal.content);
120→                        const canvasPreview = isCanvasPost ? getCanvasPreview(journal?.canvas_doc) : null;
121→                        const wholeText = isCanvasPost ? canvasPreview?.wholeText || '' : parsedContent?.wholeText || '';
122→                        const previewText = isCanvasPost ? canvasPreview?.slicedText || '' : parsedContent?.slicedText || '';
123→                        const thumbnail = isCanvasPost ? null : parsedContent?.firstImage?.src;
124→                        return (
125→                            <motion.div
126→                                key={journal.id}
127→                                className={`postcards-grid-item${isCanvasPost ? ' is-canvas-card' : ''}`}
128→                                initial={{ opacity: 0, scale: 0.95 }}
129→                                animate={{ opacity: 1, scale: 1 }}
130→                                transition={{ duration: 0.25, ease: 'easeOut' }}
131→                                onClick={(e) => viewContent(e, journal?.content, wholeText, journal?.title, userId, journal?.users?.name, journal?.users?.image_url, journal?.created_at, journal?.id, journal?.has_liked, journal?.comment_count?.[0].count, journal?.has_bookmarked, journal?.like_count?.[0].count, journal?.bookmark_count?.[0].count, journal?.users?.badge, journal?.post_type, journal?.canvas_doc, journal?.user_reaction, journal?.reaction_count?.[0]?.count || 0)}
132→                            >
133→                                {isCanvasPost ? (
134→                                    <div className="postcards-grid-img-wrap">
135→                                        <CanvasPreview canvasDoc={journal?.canvas_doc} />
136→                                    </div>
137→                                ) : thumbnail ? (
138→                                    <div className="postcards-grid-img-wrap">
139→                                        <img className="postcards-grid-thumb" src={thumbnail} alt={journal?.title ? `${journal.title} cover image` : "Post cover image"} loading="lazy" onError={handleImageFallback} />
140→                                    </div>
141→                                ) : null}
142→                                <div className="postcards-grid-body">
143→                                    <h3 className="postcards-grid-title">{journal.title.length > 32 ? `${journal.title.substring(0, 32)}...` : journal.title}</h3>
144→                                    {previewText && (
145→                                        <p className="postcards-grid-snippet">{previewText.length > 50 ? `${previewText.substring(0, 50)}...` : previewText}</p>
146→                                    )}
147→                                </div>
148→                            </motion.div>
149→                        );
150→                    })}
151→                </div>
152→            ) : (
153→            <div className="postcards-list-view">
154→            {journals.map((journal, index) => {
155→                const isCanvasPost = journal?.post_type === 'canvas';
156→                const parsedContent = ParseContent(journal.content);
157→                const canvasPreview = isCanvasPost ? getCanvasPreview(journal?.canvas_doc) : null;
158→                const wholeText = isCanvasPost ? canvasPreview?.wholeText || '' : parsedContent?.wholeText || '';
159→                const previewText = isCanvasPost ? canvasPreview?.slicedText || '' : parsedContent?.slicedText || '';
160→                const thumbnail = isCanvasPost ? null : parsedContent?.firstImage?.src;
161→                const badgeClass = journal.users.badge === 'legend' ? 'avatar-ring-legend' : journal.users.badge === 'og' ? 'avatar-ring-og' : '';
162→
163→                return(
164→                    <motion.div
165→                        key={journal.id || index}
166→                        className={`profile-postcards${isCanvasPost ? ' is-canvas-card' : ''}`}
167→                        initial={{opacity: 0, y: 12}}
168→                        animate={{opacity: 1, y: 0}}
169→                        transition={{duration: 0.3, ease: 'easeOut'}}
170→                    >
171→                        {isCanvasPost && (
172→                            <CanvasPreview canvasDoc={journal?.canvas_doc} />
173→                        )}
174→
175→                        {thumbnail && (
176→                            <img
177→                                className="card-image-banner"
178→                                src={thumbnail}
179→                                alt={journal?.title ? `${journal.title} cover image` : "Post cover image"}
180→                                loading="lazy"
181→                                onError={handleImageFallback}
182→                                onClick={(e) => viewContent(e, journal?.content, wholeText, journal?.title, userId, journal?.users?.name, journal?.users?.image_url, journal?.created_at, journal?.id, journal?.has_liked, journal?.comment_count?.[0].count, journal?.has_bookmarked, journal?.like_count?.[0].count, journal?.bookmark_count?.[0].count, journal?.users?.badge, journal?.post_type, journal?.canvas_doc, journal?.user_reaction, journal?.reaction_count?.[0]?.count || 0)}
183→                            />
184→                        )}
185→
186→                        <div className='user-profile-card-content'>
187→                            <div onClick={(e) => viewContent(e, journal?.content, wholeText, journal?.title, userId, journal?.users?.name, journal?.users?.image_url, journal?.created_at, journal?.id, journal?.has_liked, journal?.comment_count?.[0].count, journal?.has_bookmarked, journal?.like_count?.[0].count, journal?.bookmark_count?.[0].count, journal?.users?.badge, journal?.post_type, journal?.canvas_doc, journal?.user_reaction, journal?.reaction_count?.[0]?.count || 0)} className="content-container">
188→                                <div className='feed-text-content-container'>
189→                                    <div className='feed-title-content'>
190→                                        <h2 className="feed-title-profile-page">{journal.title.length > 55 ? `${journal.title.substring(0, 55)}...` : journal.title}</h2>
191→                                    </div>
192→                                    <p className="feed-text-content-profile-page">{previewText}</p>
193→                                </div>
194→                            </div>
195→
196→                            <div className="card-icons-container">
197→                                <div className='user-info-child-container'>
198→                                    <div className={`user-avatar-container ${badgeClass}`}>
199→                                        <img src={journal.users.image_url || '/assets/profile.jpg'} alt="user-profile" loading='lazy' className="user-info-avatar"/>
200→                                    </div>
201→                                    <div className="user-name-container">
202→                                        <p className="user-newsfeed-name-profile-page">{journal.users.name}</p>
203→                                        <VerifiedBadge badge={journal.users.badge} size={14} />
204→                                    </div>
205→                                    <div className="name-info-separator">•</div>
206→                                    <p className="user-post-date">{new Date(journal.created_at).toLocaleDateString('en-US', {
207→                                        month: 'long',
208→                                        day: 'numeric',
209→                                        year: 'numeric'
210→                                    })}</p>
211→
212→                                    <div className="user-post-settings">
213→                                        <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentColor"><path d="M240-400q-33 0-56.5-23.5T160-480q0-33 23.5-56.5T240-560q33 0 56.5 23.5T320-480q0 33-23.5 56.5T240-400Zm240 0q-33 0-56.5-23.5T400-480q0-33 23.5-56.5T480-560q33 0 56.5 23.5T560-480q0 33-23.5 56.5T480-400Zm240 0q-33 0-56.5-23.5T640-480q0-33 23.5-56.5T720-560q33 0 56.5 23.5T800-480q0 33-23.5 56.5T720-400Z"/></svg>
214→                                    </div>
215→                                </div>
216→                            </div>
217→                        </div>
218→                    </motion.div>
219→                )
220→            })}
221→            </div>
222→            )}
223→
224→            <div ref={ref} className='in-view-container'>
225→                {isFetchingNextPage && (
226→                    <MoonLoader size={20} color="var(--loader-color)" loading={isFetchingNextPage}/>
227→                )}
228→            </div>
229→
230→        </div>
231→        </>
232→    )
233→}
234→
235→export default VisitedProfilePostCards;
